import i18n from "i18next";
import { initReactI18next } from "react-i18next";
import { buildResources, loadFxTranslations } from "./resources";

let initPromise: Promise<void> | null = null;

export async function initFxI18n(language?: string): Promise<void> {
  if (i18n.isInitialized) {
    const lang = language ?? i18n.language ?? "en";
    const base = lang.split("-")[0];
    for (const code of [lang, base]) {
      if (!i18n.hasResourceBundle(code, "fx")) {
        i18n.addResourceBundle(code, "fx", loadFxTranslations(code), true, true);
      }
    }
    return;
  }

  if (!initPromise) {
    initPromise = i18n
      .use(initReactI18next)
      .init({
        lng: language ?? "en",
        fallbackLng: "en",
        defaultNS: "fx",
        ns: ["fx"],
        resources: buildResources(),
        interpolation: { escapeValue: false },
      })
      .then(() => undefined);
  }
  return initPromise;
}
